/* 
 * Simple, 32-bit and 64-bit clean allocator based on an implicit free list,
 * first fit placement, and boundary tag coalescing, as described in the
 * CS:APP3e text.  Blocks are aligned to double-word boundaries.  This
 * yields 8-byte aligned blocks on a 32-bit processor, and 16-byte aligned
 * blocks on a 64-bit processor.  However, 16-byte alignment is stricter
 * than necessary; the assignment only requires 8-byte alignment.  The
 * minimum block size is four words.
 *
 * This allocator uses the size of a pointer, e.g., sizeof(void *), to
 * define the size of a word.  This allocator also uses the standard
 * type uintptr_t to define unsigned integers that are the same size
 * as a pointer, i.e., sizeof(uintptr_t) == sizeof(void *).
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

/*********************************************************
 * NOTE TO STUDENTS: Before you do anything else, please
 * provide your team information in the following struct.
 ********************************************************/
team_t team = {
	/* Team name */
	"BSCS Bench",
	/* First member's full name */
	"BSCS Bench Agent",
	/* First member's NetID */
	"bscs1",
	/* Second member's full name (leave blank if none) */
	"",
	/* Second member's NetID (leave blank if none) */
	""
};

/* Basic constants and macros: */
#define WSIZE      sizeof(void *) /* Word and header/footer size (bytes) */
#define DSIZE      (2 * WSIZE)    /* Doubleword size (bytes) */
#define CHUNKSIZE  (1 << 10)      /* Extend heap by this amount (bytes) */
#define NUM_LISTS  20             /* Number of segregated free lists */

#define MAX(x, y)  ((x) > (y) ? (x) : (y))  

/* Pack a size and allocated bit into a word. */
#define PACK(size, alloc)  ((size) | (alloc))

/* Read and write a word at address p. */
#define GET(p)       (*(uintptr_t *)(p))
#define PUT(p, val)  (*(uintptr_t *)(p) = (val))

/* Read the size and allocated fields from address p. */
#define GET_SIZE(p)   (GET(p) & ~(DSIZE - 1))
#define GET_ALLOC(p)  (GET(p) & 0x1)

/* Given block ptr bp, compute address of its header and footer. */
#define HDRP(bp)  ((char *)(bp) - WSIZE)
#define FTRP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Given block ptr bp, compute address of next and previous blocks. */
#define NEXT_BLKP(bp)  ((char *)(bp) + GET_SIZE(((char *)(bp) - WSIZE)))
#define PREV_BLKP(bp)  ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

/* Given a free block pointer bp, get/set its next and prev pointers in the free list. */
#define NEXT_FREE_PTR(bp)  (*(void **)(bp))
#define PREV_FREE_PTR(bp)  (*(void **)((char *)(bp) + WSIZE))

/* Global variables: */
static char *heap_listp; /* Pointer to first block */  
static void *segregated_free_lists; /* Pointer to the array of free list heads */

/* Function prototypes for internal helper routines: */
static void *coalesce(void *bp);
static void *extend_heap(size_t words);
static void *find_fit(size_t asize);
static void place(void *bp, size_t asize);
static void insert_block(void *bp, size_t size);
static void remove_block(void *bp);
static int get_list_index(size_t size);

/* Function prototypes for heap consistency checker routines: */
static void checkblock(void *bp);
static void checkheap(bool verbose);
static void printblock(void *bp); 

/* 
 * mm_init - Initialize the memory manager.
 */
int
mm_init(void) 
{
	/* Allocate space for segregated list heads at the start of the heap. */
	if ((segregated_free_lists = mem_sbrk(NUM_LISTS * WSIZE)) == (void *)-1)
		return (-1);

	for (int i = 0; i < NUM_LISTS; i++) {
		((void **)segregated_free_lists)[i] = NULL;
	}

	/* Create the initial empty heap. */
	if ((heap_listp = mem_sbrk(4 * WSIZE)) == (void *)-1)
		return (-1);
	PUT(heap_listp, 0);                            /* Alignment padding */
	PUT(heap_listp + (1 * WSIZE), PACK(DSIZE, 1)); /* Prologue header */ 
	PUT(heap_listp + (2 * WSIZE), PACK(DSIZE, 1)); /* Prologue footer */ 
	PUT(heap_listp + (3 * WSIZE), PACK(0, 1));     /* Epilogue header */
	heap_listp += (2 * WSIZE);

	/* Extend the empty heap with a free block of CHUNKSIZE bytes. */
	if (extend_heap(CHUNKSIZE / WSIZE) == NULL)
		return (-1);
	return (0);
}

/* 
 * mm_malloc - Allocate a block with at least size bytes of payload.
 */
void *
mm_malloc(size_t size) 
{
	size_t asize;      /* Adjusted block size */
	size_t extendsize; /* Amount to extend heap if no fit */
	void *bp;

	/* Ignore spurious requests. */
	if (size == 0)
		return (NULL);

	/* Adjust block size to include overhead and alignment reqs. */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	/* Search the free list for a fit. */
	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	/* No fit found.  Get more memory and place the block. */
	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)  
		return (NULL);
	place(bp, asize);
	return (bp);
} 

/* 
 * mm_free - Free a block and use boundary tag coalescing to merge it with any adjacent free blocks.
 */
void
mm_free(void *bp)
{
	size_t size;

	/* Ignore spurious requests. */
	if (bp == NULL)
		return;

	/* Free and coalesce the block. */
	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * mm_realloc - Optimized realloc.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	void *newptr;
	size_t oldsize;
	size_t asize;

	/* If size == 0 then this is just free, and we return NULL. */
	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}

	/* If oldptr is NULL, then this is just malloc. */
	if (ptr == NULL)
		return (mm_malloc(size));

	/* Adjust block size to include overhead and alignment reqs. */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	oldsize = GET_SIZE(HDRP(ptr));

	if (oldsize >= asize) {
		if ((oldsize - asize) >= (2 * DSIZE)) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			void *next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(oldsize - asize, 0));
			PUT(FTRP(next_bp), PACK(oldsize - asize, 0));
			coalesce(next_bp);
		}
		return ptr;
	} else {
		/* Try to merge with the next block if it is free. */
		void *next_bp = NEXT_BLKP(ptr);
		size_t next_alloc = GET_ALLOC(HDRP(next_bp));
		size_t next_size = GET_SIZE(HDRP(next_bp));

		if (!next_alloc && (oldsize + next_size >= asize)) {
			remove_block(next_bp);
			size_t combined_size = oldsize + next_size;
			if (combined_size - asize >= 2 * DSIZE) {
				PUT(HDRP(ptr), PACK(asize, 1));
				PUT(FTRP(ptr), PACK(asize, 1));
				void *rem_bp = NEXT_BLKP(ptr);
				PUT(HDRP(rem_bp), PACK(combined_size - asize, 0));
				PUT(FTRP(rem_bp), PACK(combined_size - asize, 0));
				insert_block(rem_bp, combined_size - asize);
			} else {
				PUT(HDRP(ptr), PACK(combined_size, 1));
				PUT(FTRP(ptr), PACK(combined_size, 1));
			}
			return ptr;
		} 
		/* Try to merge with the previous block if it is free. */
		void *prev_bp = PREV_BLKP(ptr);
		size_t prev_alloc = GET_ALLOC(FTRP(prev_bp));
		size_t prev_size = GET_SIZE(HDRP(prev_bp));
		if (!prev_alloc && (oldsize + prev_size >= asize)) {
			remove_block(prev_bp);
			size_t combined_size = oldsize + prev_size;
			memmove(prev_bp, ptr, oldsize - DSIZE);
			PUT(HDRP(prev_bp), PACK(combined_size, 1));
			PUT(FTRP(prev_bp), PACK(combined_size, 1));
			return prev_bp;
		}
		/* Try to merge with both. */
		if (!prev_alloc && !next_alloc && (oldsize + prev_size + next_size >= asize)) {
			remove_block(prev_bp);
			remove_block(next_bp);
			size_t combined_size = oldsize + prev_size + next_size;
			memmove(prev_bp, ptr, oldsize - DSIZE);
			if (combined_size - asize >= 2 * DSIZE) {
				PUT(HDRP(prev_bp), PACK(asize, 1));
				PUT(FTRP(prev_bp), PACK(asize, 1));
				void *rem_bp = NEXT_BLKP(prev_bp);
				PUT(HDRP(rem_bp), PACK(combined_size - asize, 0));
				PUT(FTRP(rem_bp), PACK(combined_size - asize, 0));
				insert_block(rem_bp, combined_size - asize);
			} else {
				PUT(HDRP(prev_bp), PACK(combined_size, 1));
				PUT(FTRP(prev_bp), PACK(combined_size, 1));
			}
			return prev_bp;
		}
		/* Special case: block is at the end of the heap. */
		else if (GET_SIZE(HDRP(next_bp)) == 0) {
			size_t extend_size = asize - oldsize;
			if (mem_sbrk(extend_size) == (void *)-1)
				return NULL;

			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 1)); /* New epilogue header */
			return ptr;
		}
		else {
			newptr = mm_malloc(size);
			if (newptr == NULL)
				return (NULL);
			size_t copy_size = oldsize - DSIZE;
			if (size < copy_size) copy_size = size;
			memcpy(newptr, ptr, copy_size);
			mm_free(ptr);
			return (newptr);
		}
	}
}

/*
 * The following routines are internal helper routines.
 */

/*
 * get_list_index - Determine the index of the segregated free list for a given size.
 */
static int get_list_index(size_t size) {
	if (size <= 32) return 0;
	int index = 0;
	for (size_t s = 32; s < size && index < NUM_LISTS - 1; s <<= 1, index++);
	return index;
}

/*
 * insert_block - Insert a free block into the appropriate segregated free list.
 */
static void insert_block(void *bp, size_t size) {
	int index = get_list_index(size);
	void **list_head = &((void **)segregated_free_lists)[index];

	NEXT_FREE_PTR(bp) = *list_head;
	PREV_FREE_PTR(bp) = NULL;

	if (*list_head != NULL) {
		PREV_FREE_PTR(*list_head) = bp;
	}
	*list_head = bp;
}

/*
 * remove_block - Remove a free block from its segregated free list.
 */
static void remove_block(void *bp) {
	size_t size = GET_SIZE(HDRP(bp));
	int index = get_list_index(size);
	void **list_head = &((void **)segregated_free_lists)[index];

	void *next = NEXT_FREE_PTR(bp);
	void *prev = PREV_FREE_PTR(bp);

	if (prev != NULL) {
		NEXT_FREE_PTR(prev) = next;
	} else {
		*list_head = next;
	}

	if (next != NULL) {
		PREV_FREE_PTR(next) = prev;
	}
}

/*
 * coalesce - Boundary tag coalescing.
 */
static void *
coalesce(void *bp) 
{
	size_t prev_alloc = GET_ALLOC(FTRP(PREV_BLKP(bp)));
	size_t next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));
	size_t size = GET_SIZE(HDRP(bp));

	if (prev_alloc && next_alloc) {                 /* Case 1 */
		/* Nothing to coalesce */
	} else if (prev_alloc && !next_alloc) {         /* Case 2 */
		remove_block(NEXT_BLKP(bp));
		size += GET_SIZE(HDRP(NEXT_BLKP(bp)));
		PUT(HDRP(bp), PACK(size, 0));
		PUT(FTRP(bp), PACK(size, 0));
	} else if (!prev_alloc && next_alloc) {         /* Case 3 */
		remove_block(PREV_BLKP(bp));
		size += GET_SIZE(HDRP(PREV_BLKP(bp)));
		PUT(FTRP(bp), PACK(size, 0));
		PUT(HDRP(PREV_BLKP(bp)), PACK(size, 0));
		bp = PREV_BLKP(bp);
	} else {                                        /* Case 4 */
		remove_block(PREV_BLKP(bp));
		remove_block(NEXT_BLKP(bp));
		size += GET_SIZE(HDRP(PREV_BLKP(bp))) + 
		    GET_SIZE(FTRP(NEXT_BLKP(bp)));
		PUT(HDRP(PREV_BLKP(bp)), PACK(size, 0));
		PUT(FTRP(NEXT_BLKP(bp)), PACK(size, 0));
		bp = PREV_BLKP(bp);
	}

	insert_block(bp, size);
	return (bp);
}

/* 
 * extend_heap - Extend the heap with a new free block.
 */
static void *
extend_heap(size_t words) 
{
	char *bp;
	size_t size;

	/* Allocate an even number of words to maintain alignment. */
	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if ((long)(bp = mem_sbrk(size)) == -1)  
		return (NULL);

	/* Initialize free block header/footer and the epilogue header. */
	PUT(HDRP(bp), PACK(size, 0));         /* Free block header */
	PUT(FTRP(bp), PACK(size, 0));         /* Free block footer */
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1)); /* New epilogue header */

	/* Coalesce if the previous block was free. */
	return (coalesce(bp));
}

/*
 * find_fit - Find a fit for a block with asize bytes.
 */
static void *
find_fit(size_t asize)
{
	/* Search the segregated free lists for a fit. */
	for (int i = get_list_index(asize); i < NUM_LISTS; i++) {
		void *bp = ((void **)segregated_free_lists)[i];
		void *best_in_list = NULL;
		size_t min_diff = (size_t)-1;
		int count = 0;

		while (bp != NULL && count < 50) { // Limited best-fit search
			size_t bsize = GET_SIZE(HDRP(bp));
			if (asize <= bsize) {
				size_t diff = bsize - asize;
				if (diff == 0) return bp;
				if (diff < min_diff) {
					min_diff = diff;
					best_in_list = bp;
				}
			}
			bp = NEXT_FREE_PTR(bp);
			count++;
		}
		if (best_in_list != NULL) return best_in_list;
	}
	return (NULL);
}

/* 
 * place - Place a block of asize bytes at the start of the free block bp.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));   
	remove_block(bp);

	if ((csize - asize) >= (2 * DSIZE)) { 
		PUT(HDRP(bp), PACK(asize, 1));
		PUT(FTRP(bp), PACK(asize, 1));
		bp = NEXT_BLKP(bp);
		PUT(HDRP(bp), PACK(csize - asize, 0));
		PUT(FTRP(bp), PACK(csize - asize, 0));
		insert_block(bp, csize - asize);
	} else {
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
	}
}

/* 
 * The remaining routines are heap consistency checker routines. 
 */

/*
 * Requires:
 *   "bp" is the address of a block.
 *
 * Effects:
 *   Perform a minimal check on the block "bp".
 */
static void
checkblock(void *bp) 
{

	if ((uintptr_t)bp % DSIZE)
		printf("Error: %p is not doubleword aligned\n", bp);
	if (GET(HDRP(bp)) != GET(FTRP(bp)))
		printf("Error: header does not match footer\n");
}

/* 
 * checkheap - Perform a minimal check of the heap for consistency. 
 */
void
checkheap(bool verbose) 
{
	void *bp;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE ||
	    !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");
	checkblock(heap_listp);

	/* Check segregated lists */
	for (int i = 0; i < NUM_LISTS; i++) {
		void *fbp = ((void **)segregated_free_lists)[i];
		while (fbp != NULL) {
			if (GET_ALLOC(HDRP(fbp)))
				printf("Error: block in free list is marked as allocated\n");
			checkblock(fbp);
			fbp = NEXT_FREE_PTR(fbp);
		}
	}

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
	}

	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");
}

/*
 * Requires:
 *   "bp" is the address of a block.
 *
 * Effects:
 *   Print the block "bp".
 */
static void
printblock(void *bp) 
{
	size_t hsize, fsize;
	bool halloc, falloc;

	hsize = GET_SIZE(HDRP(bp));
	halloc = GET_ALLOC(HDRP(bp));  
	fsize = GET_SIZE(FTRP(bp));
	falloc = GET_ALLOC(FTRP(bp));  

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}

	printf("%p: header: [%zu:%c] footer: [%zu:%c]\n", bp, 
	    hsize, (halloc ? 'a' : 'f'), 
	    fsize, (falloc ? 'a' : 'f'));
}

